  async showHomeLocation(home_Lat, home_Long): Promise<void> {
    let coordinates: string = `${home_Lat},${home_Long}`;
    let result = await this.locationService.showLocation(coordinates);
    if (!result.success) {
      this, this.alertSerivce.showAlertError(result.message, false);
    }
  }

  async getOfficerLocation(): Promise<void> {
    // if (Capacitor.getPlatform() != "web") {
    this.showLoader = true;
    try {
      let locationResult: GeolocationResult =
        await this.locationService.getLocation();
      // console.log(locationResult);
      if (!locationResult.success) {
        this, this.alertSerivce.showAlertError(locationResult.message, false);

        this.showLoader = false;
        return;
      }

      this.OfficerLat = locationResult.position?.coords.latitude.toString();
      this.OfficerLong = locationResult.position?.coords.longitude.toString();
      this.OfficerZoom = "0";
      // console.log(this.OfficerLat, this.OfficerLong);
      // this.presentToast("تم", locationResult.message);
      this.showLoader = false;
    } catch (error) {
      this.showLoader = false;
      // this.showAlertNoReload("خطأ عند أخذ لقطة الموقع");
    }
    // }
  }

  GetLateClients() {
    this.showLoader = true;

    var lateClients: ILateClient = {
      end_date: this.endDate,
      currency_code: "0",
      officer_key: this.officer_key,
      inst_cond: "0",
      client_type_code: "1,2,3,4",
      cur_branch_code: this.cur_branch_code,
      all_currency_codes: "0",
      all_officer_keys: "0",
      all_inst_conds: "0",
      all_client_type_codes: "0",
      l_type: this.l_type,
      all_l_type: "1",
      funder_list: "0",
      all_funder: "1",
      OfficerLat: this.OfficerLat,
      OfficerLong: this.OfficerLong,
    };

    this.http
      .post<ILateClient>(
        this.env.API_URL +
          `api/Clients/LateClient?&pageNo=${this.page}&pageSize=${this.pageSize}&sortingParam=${this.sortingParam}&orderBy=${this.orderBy}`,
        lateClients
      )
      .subscribe({
        next: (data) => {
          this.reset();
          this.clients = data["result"];
          // console.log(this.clients);
          this.resultsCount = data["count"];
          // this.sortDistance();

          // this.success("تم اضافة طلب القرض بنجاح");
          this.showLoader = false;
        },
        error: (err) => {
          console.log(err.error);
          // this.fail(err.error);
          this.showLoader = false;
        },
      });
  }

